<template><div class="page-wrap"><section class="page-hero"><div><span class="eyebrow">DEPARTMENT DIRECTORY</span><h1>科室管理</h1><p>维护平台诊疗科室、展示顺序与服务说明</p></div><el-button class="hero-action" :icon="Plus" @click="openAdd">新增科室</el-button></section><section class="content-card"><div class="card-toolbar"><div><h2>科室档案</h2><p>当前共维护 {{ list.length }} 个诊疗科室</p></div><div class="toolbar-actions"><el-input v-model="keyword" :prefix-icon="Search" placeholder="搜索科室名称" clearable/><el-button class="soft-btn" :icon="Refresh" @click="loadData">刷新</el-button><el-button type="primary" class="primary-btn" :icon="Plus" @click="openAdd">新增科室</el-button></div></div><el-table :data="filtered" v-loading="loading" class="admin-table"><el-table-column label="科室" min-width="190"><template #default="{row}"><div class="dept-cell"><span>{{ row.name.slice(0,1) }}</span><div><strong>{{row.name}}</strong><small>DEPARTMENT · {{String(row.id).padStart(3,'0')}}</small></div></div></template></el-table-column><el-table-column prop="description" label="科室说明" min-width="320" show-overflow-tooltip><template #default="{row}">{{row.description||'暂未填写科室说明'}}</template></el-table-column><el-table-column prop="sort" label="排序" width="100" align="center"><template #default="{row}"><el-tag effect="plain" round>{{row.sort}}</el-tag></template></el-table-column><el-table-column label="创建时间" min-width="175"><template #default="{row}"><span class="muted">{{formatTime(row.createTime)}}</span></template></el-table-column><el-table-column label="操作" width="150" fixed="right"><template #default="{row}"><el-button link type="primary" @click="openEdit(row)">编辑</el-button><el-button link type="danger" @click="remove(row)">删除</el-button></template></el-table-column><template #empty><el-empty description="暂无科室数据"/></template></el-table></section><el-dialog v-model="dialog" :title="form.id?'编辑科室':'新增科室'" width="520px" destroy-on-close><el-form ref="formRef" :model="form" :rules="rules" label-position="top" class="dialog-form"><el-form-item label="科室名称" prop="name"><el-input v-model="form.name" placeholder="例如：心血管内科" maxlength="50"/></el-form-item><el-form-item label="排序号" prop="sort"><el-input-number v-model="form.sort" :min="0" :max="999" style="width:100%"/></el-form-item><el-form-item label="科室说明"><el-input v-model="form.description" type="textarea" :rows="4" maxlength="500" show-word-limit placeholder="介绍科室诊疗方向和特色"/></el-form-item></el-form><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" class="primary-btn" :loading="saving" @click="save">保存科室</el-button></template></el-dialog></div></template>
<script setup lang="ts">
import { computed, onMounted, reactive, ref } from 'vue';import { ElMessage, ElMessageBox, type FormInstance, type FormRules } from 'element-plus';import { Plus,Search,Refresh } from '@element-plus/icons-vue';import { addDepartment,deleteDepartment,getDepartments,updateDepartment } from '@/api/department';import type { Department } from '@/types';
const loading=ref(false),saving=ref(false),dialog=ref(false),keyword=ref(''),list=ref<Department[]>([]),formRef=ref<FormInstance>();const form=reactive<Department>({name:'',description:'',sort:0});const rules:FormRules={name:[{required:true,message:'请输入科室名称',trigger:'blur'}]};const filtered=computed(()=>list.value.filter(x=>!keyword.value||x.name.includes(keyword.value.trim())));const formatTime=(v?:string)=>v?new Date(v).toLocaleString('zh-CN'):'--';const loadData=async()=>{loading.value=true;try{list.value=(await getDepartments()).data.data||[]}finally{loading.value=false}};const reset=()=>Object.assign(form,{id:undefined,name:'',description:'',sort:0});const openAdd=()=>{reset();dialog.value=true};const openEdit=(row:Department)=>{Object.assign(form,row);dialog.value=true};const save=async()=>{if(!await formRef.value?.validate().catch(()=>false))return;saving.value=true;try{form.id?await updateDepartment({...form}):await addDepartment({...form});ElMessage.success(form.id?'科室更新成功':'科室新增成功');dialog.value=false;await loadData()}finally{saving.value=false}};const remove=async(row:Department)=>{await ElMessageBox.confirm(`确定删除“${row.name}”吗？`,'删除科室',{type:'warning'});await deleteDepartment(row.id!);ElMessage.success('科室已删除');loadData()};onMounted(loadData)
</script>
<style scoped>.hero-action{position:relative;z-index:2;border:1px solid rgba(255,255,255,.25);border-radius:11px;background:rgba(255,255,255,.13);color:#fff}.dept-cell{display:flex;align-items:center;gap:11px}.dept-cell>span{width:39px;height:39px;display:flex;align-items:center;justify-content:center;border-radius:12px;background:#e3f4f1;color:#087f84;font-weight:800}.dept-cell strong,.dept-cell small{display:block}.dept-cell strong{font-size:13px}.dept-cell small{margin-top:3px;color:#a0adb2;font-size:8px;letter-spacing:.5px}</style>
